/**
 * GET /api/admin/debug-dasha
 * Temporary admin-only diagnostic endpoint.
 * Checks Vedic chart cache + dasha DB state, then forces a fresh Vedic API call.
 * Only accessible to shomty@hotmail.com.
 */

import { NextResponse } from "next/server";
import { auth } from "@/lib/auth";
import { db } from "@/lib/db";
import { kvGet, kvDelete } from "@/lib/kv/helpers";
import { kvKeys } from "@/lib/kv/keys";
import { fetchVedicNatalChart, VedicApiError } from "@/lib/astro/vedicApiClient";
import { storeDashasFromChart } from "@/lib/astro/dashaService";
import type { VedicChart } from "@/lib/astro/types";

export const runtime = "nodejs";

export async function GET() {
  const session = await auth();
  if (session?.user?.email !== "shomty@hotmail.com") {
    return NextResponse.json({ error: "Forbidden" }, { status: 403 });
  }

  const userId = session.user.id!;
  const now = new Date();

  // ── 1. DB state
  const birthProfile = await db.birthProfile.findUnique({
    where: { userId },
    select: {
      id: true,
      birthName: true,
      birthCity: true,
      birthCountry: true,
      birthDate: true,
      birthTimeKnown: true,
      birthHour: true,
      birthMinute: true,
      latitude: true,
      longitude: true,
      gender: true,
      profileVersion: true,
    },
  });

  const dashaCount = await db.dasha.count({ where: { userId } });
  const activeMaha = await db.dasha.findFirst({
    where: { userId, level: "MAHADASHA", startDate: { lte: now }, endDate: { gte: now } },
  });

  // ── 2. KV cache state
  const kvCached = await kvGet(kvKeys.vedicChart(userId));

  // ── 3. Force fresh Vedic API call and capture raw response structure
  let vedicResult: "success" | "error" = "error";
  let vedicError: string | null = null;
  let newDashaCount = 0;
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  let rawResponseSample: any = null;

  if (birthProfile) {
    await kvDelete(kvKeys.vedicChart(userId));

    try {
      const d = new Date(birthProfile.birthDate);
      const dateOfBirth = [
        d.getUTCFullYear(),
        String(d.getUTCMonth() + 1).padStart(2, "0"),
        String(d.getUTCDate()).padStart(2, "0"),
      ].join("-");
      const hour = birthProfile.birthTimeKnown ? (birthProfile.birthHour ?? 12) : 12;
      const minute = birthProfile.birthTimeKnown ? (birthProfile.birthMinute ?? 0) : 0;
      const timeOfBirth = `${String(hour).padStart(2, "0")}:${String(minute).padStart(2, "0")}`;
      const location = [birthProfile.birthCity, birthProfile.birthCountry].filter(Boolean).join(", ");
      const genderMap: Record<string, "male" | "female" | "other"> = {
        male: "male", female: "female", other: "other",
      };
      const gender = genderMap[birthProfile.gender ?? ""] ?? "other";
      const requestPayload = { dateOfBirth, timeOfBirth, location, isTimeApproximate: !birthProfile.birthTimeKnown, gender, name: birthProfile.birthName };

      const chart = await fetchVedicNatalChart(requestPayload);

      const raw = (chart as VedicChart).rawResponse as unknown as Record<string, unknown>;

      // Capture top-level keys and dasha path for diagnosis
      rawResponseSample = {
        topLevelKeys: Object.keys(raw ?? {}),
        chartD1Keys: raw?.chartD1 ? Object.keys(raw.chartD1 as object) : "MISSING",
        hasChartD1: "chartD1" in (raw ?? {}),
        // eslint-disable-next-line @typescript-eslint/no-explicit-any
        chartD1DashasKeys: (raw?.chartD1 as any)?.dashas ? Object.keys((raw.chartD1 as any).dashas) : "MISSING",
        // eslint-disable-next-line @typescript-eslint/no-explicit-any
        vimshottariKeys: (raw?.chartD1 as any)?.dashas?.vimshottari
          // eslint-disable-next-line @typescript-eslint/no-explicit-any
          ? Object.keys((raw.chartD1 as any).dashas.vimshottari)
          : "MISSING",
        // eslint-disable-next-line @typescript-eslint/no-explicit-any
        dashaPeriodsSample: (raw?.chartD1 as any)?.dashas?.vimshottari?.dashaPeriods?.slice(0, 2) ?? "MISSING",
        // eslint-disable-next-line @typescript-eslint/no-explicit-any
        rawDashasValue: (raw?.chartD1 as any)?.dashas ?? "NOT FOUND AT chartD1.dashas",
      };

      await storeDashasFromChart(userId, raw as unknown as Parameters<typeof storeDashasFromChart>[1]);
      vedicResult = "success";
      newDashaCount = await db.dasha.count({ where: { userId } });
    } catch (e) {
      if (e instanceof VedicApiError) {
        vedicError = `HTTP ${e.status} — body: ${e.body}`;
      } else {
        vedicError = e instanceof Error ? `${e.message}\n${e.stack}` : String(e);
      }
    }
  }

  const newActiveMaha = await db.dasha.findFirst({
    where: { userId, level: "MAHADASHA", startDate: { lte: now }, endDate: { gte: now } },
  });

  return NextResponse.json({
    userId,
    birthProfileExists: !!birthProfile,
    birthCity: birthProfile?.birthCity,
    profileVersion: birthProfile?.profileVersion,
    dashaCountBefore: dashaCount,
    activeMahaBefore: activeMaha?.planetName ?? null,
    kvCachedBefore: kvCached !== null,
    vedicApiFreshFetch: vedicResult,
    vedicApiError: vedicError,
    dashaCountAfter: newDashaCount,
    activeMahaAfter: newActiveMaha?.planetName ?? null,
    rawResponseSample,
    requestPayloadSent: birthProfile ? {
      dateOfBirth: (() => { const d = new Date(birthProfile.birthDate); return [d.getUTCFullYear(), String(d.getUTCMonth()+1).padStart(2,"0"), String(d.getUTCDate()).padStart(2,"0")].join("-"); })(),
      location: [birthProfile.birthCity, birthProfile.birthCountry].filter(Boolean).join(", "),
      gender: birthProfile.gender,
      name: birthProfile.birthName,
      birthTimeKnown: birthProfile.birthTimeKnown,
    } : null,
    now: now.toISOString(),
  });
}
